import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Activity, ShieldCheck, Box } from 'lucide-react';

const LiveMarketPage = () => {
    const { token } = useContext(AuthContext);

    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) initializeStocks(res.data[0].holdings);
            } catch (err) { console.error("VAULT_SYNC_ERROR"); }
        };
        fetchVault();
    }, []);

    const initializeStocks = (holdingsData) => {
        try {
            let tickers = typeof holdingsData === 'string' ? JSON.parse(holdingsData) : holdingsData;
            if (typeof tickers === 'string') tickers = JSON.parse(tickers);
            setStocks(tickers.map(t => ({ 
                ticker: t, 
                price: Math.floor(Math.random() * 2000) + 500, 
                change: 0.00 
            })));
        } catch (e) { setStocks([]); }
    };

    useEffect(() => {
        if (!token) return;
        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);
        ws.onopen = () => setIsConnected(true);
        ws.onmessage = () => {
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 12;
                return { 
                    ...s, 
                    price: parseFloat((s.price + move).toFixed(2)), 
                    change: parseFloat(move.toFixed(2)) 
                };
            }));
        };
        ws.onclose = () => setIsConnected(false);
        return () => ws.close();
    }, [token, currentIndex]);

    const navigate = (dir) => {
        let newIdx = currentIndex + dir;
        if (newIdx >= 0 && newIdx < history.length) {
            setCurrentIndex(newIdx);
            initializeStocks(history[newIdx].holdings);
        }
    };

    const activeNode = history[currentIndex];

    return (
        <div style={appWrapper}>
            <div style={terminalContainer}>
                {/* ── Fixed Header (Pinned) ── */}
                <header style={headerSection}>
                    <div style={navRow}>
                        <button 
                            onClick={() => navigate(1)} 
                            disabled={currentIndex === history.length - 1}
                            style={navBtn(currentIndex === history.length - 1)}
                        >
                            <ChevronLeft size={24}/> <span style={{fontSize: '1rem'}}>PREVIOUS</span>
                        </button>

                        <div style={nodeDisplay}>
                            <Box size={20} color="#10b981" />
                            <span style={nodeTitle}>{activeNode ? activeNode.goal : 'CORE_SYNCING...'}</span>
                        </div>

                        <button 
                            onClick={() => navigate(-1)} 
                            disabled={currentIndex === 0}
                            style={navBtn(currentIndex === 0)}
                        >
                            <span style={{fontSize: '1rem'}}>NEXT</span> <ChevronRight size={24}/>
                        </button>
                    </div>

                    <div style={statusRow}>
                        <div style={statusItem(isConnected)}>
                            <Activity size={18} /> {isConnected ? 'LIVE_STREAM_ACTIVE' : 'OFFLINE'}
                        </div>
                        <div style={riskItem}>
                            <ShieldCheck size={18} /> EXPOSURE: {activeNode?.risk_score || 0}%
                        </div>
                        <div style={counterTag}>{currentIndex + 1} / {history.length}</div>
                    </div>
                </header>

                {/* ── Internal Scrollable Grid ── */}
                <main style={scrollContent}>
                    <div style={gridContainer}>
                        {stocks.map((stock, i) => (
                            <div key={i} style={stockCard(stock.change >= 0)}>
                                <div style={cardTop}>
                                    <span style={tickerSymbol}>{stock.ticker}</span>
                                    <Zap size={22} color={stock.change >= 0 ? "#10b981" : "#ef4444"} />
                                </div>
                                <div style={priceLabel}>LAST_TRADED_PRICE</div>
                                <div style={priceValue}>₹{stock.price.toLocaleString()}</div>
                                <div style={changeValue(stock.change >= 0)}>
                                    {stock.change >= 0 ? <TrendingUp size={22}/> : <TrendingDown size={22}/>}
                                    {stock.change >= 0 ? '+' : ''}{stock.change}%
                                </div>
                            </div>
                        ))}
                    </div>
                </main>
            </div>
        </div>
    );
};

/* --- Visual Styles (Focused on Big Text & Spacing) --- */
const appWrapper = {
    height: 'calc(100vh - 70px)',
    width: '100%',
    display: 'flex',
    justifyContent: 'center',
    background: '#07080a',
    padding: '25px',
    boxSizing: 'border-box',
    overflow: 'hidden' 
};

const terminalContainer = {
    width: '100%',
    maxWidth: '1300px',
    height: '100%',
    display: 'flex',
    flexDirection: 'column',
    background: '#0a0b0e',
    borderRadius: '24px',
    border: '1px solid #1a1d23',
    boxShadow: '0 30px 70px rgba(0,0,0,0.7)',
    overflow: 'hidden'
};

const headerSection = {
    padding: '1.5rem 2.5rem',
    background: '#0d0f14',
    borderBottom: '2px solid #1a1d23',
    flexShrink: 0
};

const navRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.2rem' };
const navBtn = (disabled) => ({
    background: 'none', border: 'none', color: disabled ? '#333' : '#10b981',
    cursor: disabled ? 'default' : 'pointer', fontWeight: 900,
    display: 'flex', alignItems: 'center', gap: '8px', fontFamily: 'monospace'
});

const nodeDisplay = { 
    display: 'flex', alignItems: 'center', gap: '15px', background: '#111318', 
    padding: '10px 20px', borderRadius: '10px', border: '1px solid #1a1d23',
    maxWidth: '65%'
};

const nodeTitle = { fontSize: '1rem', fontWeight: 800, color: '#fff', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' };

const statusRow = { display: 'flex', gap: '2.5rem', alignItems: 'center' };
const statusItem = (on) => ({ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.8rem', fontWeight: 900, color: on ? '#10b981' : '#ef4444', fontFamily: 'monospace' });
const riskItem = { display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.8rem', fontWeight: 900, color: '#888', fontFamily: 'monospace' };
const counterTag = { marginLeft: 'auto', fontSize: '0.8rem', color: '#10b981', background: 'rgba(16,185,129,0.1)', padding: '4px 12px', borderRadius: '6px', fontWeight: 900 };

const scrollContent = { 
    flex: 1, 
    padding: '2.5rem', 
    overflowY: 'auto',
    scrollbarWidth: 'thin'
};

const gridContainer = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '2rem' };

const stockCard = (up) => ({
    padding: '2rem', background: '#111318', border: '1px solid #1a1d23',
    borderRadius: '18px', borderLeft: `6px solid ${up ? '#10b981' : '#ef4444'}`
});

const cardTop = { display: 'flex', justifyContent: 'space-between', marginBottom: '1.2rem' };
const tickerSymbol = { fontSize: '1.1rem', fontWeight: 900, color: '#10b981', fontFamily: 'monospace', letterSpacing: '0.1em' };
const priceLabel = { fontSize: '0.65rem', color: '#555', fontWeight: 800, marginBottom: '5px', letterSpacing: '0.05em' };
const priceValue = { fontSize: '2.6rem', fontWeight: 900, color: '#fff', fontFamily: 'monospace' };
const changeValue = (up) => ({ marginTop: '15px', fontSize: '1.3rem', fontWeight: 900, color: up ? '#10b981' : '#ef4444', display: 'flex', alignItems: 'center', gap: '10px' });

export default LiveMarketPage;
